// ─── TOAST NOTIFICATION ───────────────────────────
function Toast({message,type="success",onDone}) {
  const cb=useRef(onDone);cb.current=onDone;
  // v10.36.1 #2 — duración extendida (15s) para mensajes de "candado de seguridad" del bridge,
  // que llegan con texto explicativo largo del backend RAISE. Karla necesita tiempo para leer
  // qué hacer (marcar No pagada, capturar ref, etc.) antes de que el toast desaparezca.
  const isSecurityLock = type==="error" && typeof message==="string" && message.includes("candado de seguridad");
  useEffect(()=>{
    const dur = isSecurityLock ? 15000 : (type==="error"?7000:3200);
    const t=setTimeout(()=>cb.current(),dur);
    return ()=>clearTimeout(t);
  },[type, isSecurityLock]);
  const bg={success:C.ok,error:C.dn,warning:C.wn,info:"#007aff"}[type]||C.ok;
  const icon={success:"✅",error:"❌",warning:"⚠️",info:"ℹ️"}[type]||"✅";
  return <div style={{
    position:"fixed",bottom:24,left:"50%",transform:"translateX(-50%)",
    background:bg,color:"#fff",
    padding:"12px 24px",borderRadius:14,
    fontSize:13,fontWeight:600,fontFamily:"'Poppins',sans-serif",
    boxShadow:"0 8px 32px rgba(0,0,0,.18)",zIndex:9999,
    display:"flex",alignItems:"center",gap:8,
    animation:"toastIn .3s ease",
    // v10.36.1 #2 — mensajes largos del backend RAISE necesitan wrap/word-break
    maxWidth: isSecurityLock ? 520 : "90%",
    whiteSpace:"pre-wrap",
    wordBreak:"break-word",
    lineHeight:1.45,
    textAlign: isSecurityLock ? "left" : "center",
  }}>{icon} {message}</div>;
}

// ─── ESC CLOSE HOOK ───────────────────────────────
// ─── ESC CLOSE HOOK (stack-based: only topmost modal closes) ──
const escStack={s:[],push(fn){this.s.push(fn)},pop(fn){const i=this.s.lastIndexOf(fn);if(i>=0)this.s.splice(i,1)},fire(){if(this.s.length>0)this.s[this.s.length-1]()}};
if(typeof document!=="undefined"&&!escStack._bound){escStack._bound=true;document.addEventListener("keydown",e=>{if(e.key==="Escape"){const tag=e.target?.tagName;if(tag==="INPUT"||tag==="TEXTAREA"||tag==="SELECT")return;escStack.fire()}})}
function useEscClose(onClose) {
  const ref=useRef(onClose);ref.current=onClose;
  useEffect(()=>{const fn=()=>ref.current();escStack.push(fn);return ()=>escStack.pop(fn)},[]);
}

// ─── FIRST-TIME CONTEXTUAL HINTS ──────────────────
function FirstTimeHint({hintKey,text,color=C.ac,role}) {
  const storageKey="pf-hint-"+role+"-"+hintKey;
  const [show,setShow]=useState(false);
  useEffect(()=>{try{const seen=localStorage.getItem(storageKey);if(!seen)setShow(true)}catch{}},[storageKey]);
  const dismiss=e=>{e.stopPropagation();setShow(false);try{localStorage.setItem(storageKey,"1")}catch{}};
  if(!show)return null;
  return <div style={{background:color+"10",border:"1.5px solid "+color+"30",borderRadius:10,padding:"8px 12px",marginBottom:8,display:"flex",alignItems:"center",gap:8,animation:"toastIn .3s ease"}}>
    <span style={{fontSize:11,color,fontWeight:600,flex:1,lineHeight:1.4}}>💡 {text}</span>
    <button onClick={dismiss} style={{background:color+"20",border:"none",color,borderRadius:6,padding:"3px 8px",fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"'Poppins',sans-serif",flexShrink:0}}>Entendido</button>
  </div>;
}

// ─── LOGIN ─────────────────────────────────────────
function Login({onLogin}) {
  const [username,setUsername] = useState("");
  const [password,setPassword] = useState("");
  const [error,setError] = useState("");
  const [loading,setLoading] = useState(false);
  const submit = async () => {
    if (!username || !password) return setError("Escribe usuario y contraseña");
    setLoading(true); setError("");
    try {
      const user = await db.login(username.toLowerCase().trim(), password);
      if (user) { onLogin(user.role, user.display_name, user.username); }
      else { setError("Usuario o contraseña incorrectos"); }
    } catch { setError("Error de conexión"); }
    setLoading(false);
  };
  return (
    <div style={{minHeight:"100vh",background:C.bg,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Poppins',sans-serif"}}>
      <link href={FNT} rel="stylesheet"/>
      <div style={{textAlign:"center",maxWidth:400,width:"100%",padding:"0 24px"}}>
        <img src={LOGO} alt="PrintFlow" style={{width:120,height:120,marginBottom:12,borderRadius:20,display:"block",margin:"0 auto 12px"}}/>
        <h1 style={{fontSize:34,fontWeight:800,color:C.tx,textTransform:"uppercase",margin:"0 0 8px"}}>PrintFlow</h1>
        <p style={{fontSize:11,color:C.t2,textTransform:"uppercase",margin:"0 0 32px"}}>Sistema de Producción</p>
        <div style={{textAlign:"left",marginBottom:12}}>
          <label style={lbl}>Usuario</label>
          <input style={inp} value={username} onChange={e=>setUsername(e.target.value)} placeholder="Ej: gerardo, noemi, admin" onKeyDown={e=>e.key==="Enter"&&submit()}/>
        </div>
        <div style={{textAlign:"left",marginBottom:16}}>
          <label style={lbl}>Contraseña</label>
          <input style={inp} type="password" value={password} onChange={e=>setPassword(e.target.value)} placeholder="Contraseña" onKeyDown={e=>e.key==="Enter"&&submit()}/>
        </div>
        {error && <div style={{color:C.dn,fontSize:12,fontWeight:600,marginBottom:12}}>{error}</div>}
        <button onClick={submit} disabled={loading} style={{...bt(loading?"#d1d1d6":C.ac),width:"100%",justifyContent:"center",padding:"14px",fontSize:15,borderRadius:14,cursor:loading?"not-allowed":"pointer"}}>{loading?"⏳ Verificando...":"Entrar"}</button>
      </div>
    </div>
  );
}

